function fetchData(url) {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      resolve(`Data from ${url}`);
    }, 1000);
  });
}

fetchData('https://api.example.com').then(data => {
  console.log(data);
});

async function getData() {
  try {
    const data = await fetchData('https://api.example.com');
    console.log(data);
  } catch (error) {
    console.error('Error:', error);
  }
}

getData();

async function fetchMultiple() {
  const urls = ['url1', 'url2', 'url3'];
  const promises = urls.map(url => fetchData(url));
  const results = await Promise.all(promises);
  console.log(results);
}

fetchMultiple();

async function fetchWithConcurrencyLimit(urls, limit) {
  let i = 0;
  const results = [];
  async function worker() {
    while(i < urls.length) {
      const current = i++;
      results[current] = await fetchData(urls[current]);
    }
  }

  const workers = Array(limit).fill(worker).map(w => w());
  await Promise.all(workers);
  return results;
}

fetchWithConcurrencyLimit(['url1', 'url2', 'url3', 'url4'], 2).then(console.log);

